//! third-eye CLI.
//!
//!   third-eye watch <video> [opts]   # run the cadence governor (P1)
//!
//! opts:
//!   --decode-fps <f>   decode at f fps (default: source rate)
//!   --scale <WxH>      scale frames before processing
//!   --max <n>          stop after n decoded frames
//!   --target-fps <f>   real-time rate to sustain (default 30)
//!   --batch <n>        frames per frf dispatch (default 16)
//!   --verbose          print per-batch convergence

use third_eye::cadence::{CadenceConfig, run};

/// A perception frame stream, sourced EITHER from an mp4 (ffmpeg decode) OR from a raw RGB24 stream
/// on stdin (the in-memory transport — same `Frame` shape, no mp4 encode/decode hop). The two paths
/// converge on the identical `frffmpeg::decode::Frame` iterator, so every read-only perception
/// subcommand feeds the EXACT same vision -> track -> scene -> publish pipeline regardless of source.
///
/// Parsed once from the args, then handed to the subcommand as a boxed `Iterator<Item =
/// io::Result<Frame>>` — the subcommand's per-frame loop is untouched (no forked pipeline).
struct FrameInput {
    iter: Box<dyn Iterator<Item = std::io::Result<frffmpeg::decode::Frame>>>,
    /// Effective output fps (mp4: source rate or --decode-fps; raw: the WxH@fps spec). Used by the
    /// cadence-governed `run` report; the dims travel in `source` (and on every `Frame`).
    fps: f64,
    /// Human label of the source, for the report line.
    source: String,
}

/// Parse a raw-stream spec `WxH@fps` (e.g. `640x360@24`). Returns `(w, h, fps)`.
fn parse_rgb_stream_spec(spec: &str) -> Result<(u32, u32, f64), String> {
    let (dims, fps) = spec
        .split_once('@')
        .ok_or_else(|| format!("--rgb-stream expects WxH@fps, got '{spec}'"))?;
    let (w, h) = dims
        .split_once('x')
        .ok_or_else(|| format!("--rgb-stream expects WxH@fps, got '{spec}'"))?;
    let w: u32 = w.parse().map_err(|_| format!("bad width in '{spec}'"))?;
    let h: u32 = h.parse().map_err(|_| format!("bad height in '{spec}'"))?;
    let fps: f64 = fps.parse().map_err(|_| format!("bad fps in '{spec}'"))?;
    if w == 0 || h == 0 {
        return Err(format!("--rgb-stream dimensions must be non-zero, got '{spec}'"));
    }
    Ok((w, h, fps))
}

impl FrameInput {
    /// Build the frame stream for a perception subcommand. When `rgb_stream` is set, read raw RGB24
    /// frames from STDIN at the given `WxH@fps` (the `path` positional is then ignored / may be `-`);
    /// otherwise probe + ffmpeg-decode the `path` mp4 under the usual decode options.
    ///
    /// `cmd` names the subcommand for error messages; on any failure it prints + `exit(1)`.
    fn open(
        cmd: &str,
        path: &str,
        rgb_stream: Option<&str>,
        decode_fps: Option<f64>,
        scale: Option<(u32, u32)>,
        max_frames: Option<u64>,
    ) -> FrameInput {
        use frffmpeg::decode::{DecodeOptions, Decoder, RawFrameSource, probe};
        if let Some(spec) = rgb_stream {
            let (w, h, fps) = match parse_rgb_stream_spec(spec) {
                Ok(v) => v,
                Err(e) => {
                    eprintln!("third-eye {cmd}: {e}");
                    std::process::exit(1);
                }
            };
            // Raw RGB24 over stdin — the in-memory transport (no ffmpeg, no mp4 hop). A renderer
            // pipes packed top-down RGB24 frames straight in; pts is reconstructed from fps.
            let stdin = std::io::stdin();
            let src = match RawFrameSource::new(stdin, w, h, fps, max_frames) {
                Ok(s) => s,
                Err(e) => {
                    eprintln!("third-eye {cmd}: raw stream open failed: {e}");
                    std::process::exit(1);
                }
            };
            FrameInput {
                iter: Box::new(src),
                fps,
                source: format!("raw RGB24 stdin {w}x{h}@{fps} (in-memory, no mp4 hop)"),
            }
        } else {
            let info = match probe(path) {
                Ok(i) => i,
                Err(e) => {
                    eprintln!("third-eye {cmd}: probe failed: {e}");
                    std::process::exit(1);
                }
            };
            let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
            let dec = match Decoder::open(path, &info, &opts) {
                Ok(d) => d,
                Err(e) => {
                    eprintln!("third-eye {cmd}: open failed: {e}");
                    std::process::exit(1);
                }
            };
            let (w, h) = dec.dimensions();
            let fps = decode_fps.unwrap_or_else(|| info.fps());
            FrameInput {
                iter: Box::new(dec),
                fps,
                source: format!("mp4 {path} ({w}x{h}, ffmpeg decode)"),
            }
        }
    }
}

fn main() {
    let args: Vec<String> = std::env::args().collect();
    if args.len() < 3 {
        usage();
    }
    match args[1].as_str() {
        "watch" => {}
        "detect" => return run_detect(&args[2..]),
        "track" => return run_track(&args[2..]),
        "orient" => return run_orient(&args[2..]),
        "spinor" => return run_spinor(&args[2..]),
        "intel" => return run_intel(&args[2..]),
        "interactions" => return run_interactions(&args[2..]),
        "predict" => return run_predict(&args[2..]),
        "scene" => return run_scene(&args[2..]),
        "affordances" => return run_affordances(&args[2..]),
        "metacog" => return run_metacog(&args[2..]),
        "publish" => return run_publish(&args[2..]),
        "run" => return run_pipeline(&args[2..]),
        _ => usage(),
    }

    let path = args[2].clone();
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut cfg = CadenceConfig::default();

    let rest = &args[3..];
    let mut i = 0;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => {
                decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok());
                i += 2;
            }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) {
                        scale = Some((w, h));
                    }
                }
                i += 2;
            }
            "--max" => {
                max_frames = rest.get(i + 1).and_then(|s| s.parse().ok());
                i += 2;
            }
            "--target-fps" => {
                if let Some(f) = rest.get(i + 1).and_then(|s| s.parse().ok()) {
                    cfg.target_fps = f;
                }
                i += 2;
            }
            "--batch" => {
                if let Some(n) = rest.get(i + 1).and_then(|s| s.parse().ok()) {
                    cfg.batch = n;
                }
                i += 2;
            }
            "--verbose" => {
                cfg.verbose = true;
                i += 1;
            }
            _ => i += 1,
        }
    }

    match run(&path, decode_fps, scale, max_frames, &cfg) {
        Ok(r) => {
            println!("third-eye cadence report");
            println!("  decoded      : {}", r.frames_decoded);
            println!("  processed    : {}", r.frames_processed);
            println!("  skipped      : {}", r.frames_skipped);
            println!(
                "  value-door   : {} (per-frame work vs dispatch cost)",
                r.light
            );
            println!("  stride       : {} (converged)", r.converged_stride);
            println!("  effective fps: {:.2} (stable sample rate)", r.effective_fps);
            println!(
                "  processing   : {:.1} frames/s (machine ceiling, cold)",
                r.processing_fps
            );
            println!("  wall         : {:.3}s", r.wall_s);
            println!("  mean motion  : {:.4} (scene activity 0..1)", r.mean_motion);
            println!(
                "  corridor     : published {} delivered {} peak_in_flight {}",
                r.published, r.delivered, r.peak_in_flight
            );
        }
        Err(e) => {
            eprintln!("third-eye watch: {e}");
            std::process::exit(1);
        }
    }
}

fn usage() -> ! {
    eprintln!(
        "Usage:\n  \
         third-eye watch <video> [--decode-fps f] [--scale WxH] [--max n] [--target-fps f] [--batch n] [--verbose]\n  \
         third-eye detect <video> [--decode-fps f] [--scale WxH] [--max n] [--dump-frame k] [--dump-dir d] [--verbose]\n  \
         third-eye track <video> [--decode-fps f] [--scale WxH] [--max n] [--verbose]\n  \
         third-eye orient <video> [--decode-fps f] [--scale WxH] [--max n]\n  \
         third-eye spinor <video> [--decode-fps f] [--scale WxH] [--max n]\n  \
         third-eye intel <video> [--decode-fps f] [--scale WxH] [--max n] [--c-max v] [--static-cam] [--object-priors priors.json]\n  \
         third-eye interactions <video> [--decode-fps f] [--scale WxH] [--max n] [--c-max v] [--static-cam] [--object-priors priors.json] [--verbose]\n  \
         (--object-priors = recon->third-eye feedback: per-track MATERIAL/MASS/INERTIA JSON grounds the physics with material-weighted masses)\n  \
         third-eye predict <video> [--decode-fps f] [--scale WxH] [--max n] [--horizon-frames N] [--c-max v] [--static-cam] [--verbose]\n  \
         third-eye scene <video> [--decode-fps f] [--scale WxH] [--max n] [--c-max v] [--static-cam] [--verbose]   (scene-level relational read: moving objects + grab/manipulation; robust to regime-abstain)\n  \
         third-eye affordances <video> [--decode-fps f] [--scale WxH] [--max n] [--c-max v] [--static-cam] [--object-priors priors.json] [--hand-reach r] [--max-impulse j] [--verbose]   (CERTIFIED AGENCY: what Thoth can DO — graspable/pushable/droppable affordances + a sample counterfactual, derived from what the picture PROVES; abstains on a hand)\n  \
         third-eye metacog <video> [--decode-fps f] [--scale WxH] [--max n] [--c-max v] [--static-cam] [--object-priors priors.json] [--plateau-window N] [--verbose]   (C0-C3 metacognitive gate per tick: certified-gnosis score + carried shadow + framework audit; the discipline = score rose OR shadow exposed)\n  \
         third-eye publish <video> [--decode-fps f] [--scale WxH] [--max n] [--out file.aeon] [--verbose]\n  \
         third-eye run <video> [--decode-fps f] [--scale WxH] [--max n] [--target-fps f] [--out file.aeon] [--static-cam] [--motion-deblur [--motion-deblur-angle deg] [--motion-deblur-length px] [--motion-deblur-iters n]] [--verbose]\n  \
         (--static-cam: fixed camera, e.g. a desk webcam — disables global-motion compensation so a moving object is not mistaken for camera pan)\n  \
         (--motion-deblur: OPTIONAL per-frame Richardson-Lucy motion-deblur pre-pass BEFORE detection — default OFF. Auto-estimates the PSF per frame unless --motion-deblur-angle/--motion-deblur-length pin it. Also enabled by env THIRD_EYE_MOTION_DEBLUR=1.)\n  \
         (run = the full cadence-governed pipeline: decode -> stride -> detect -> track -> admit -> publish)\n  \
         RAW IN-MEMORY TRANSPORT (no mp4 hop): detect/track/scene/run accept --rgb-stream WxH@fps and read packed\n  \
         top-down RGB24 frames from STDIN instead of decoding a video — same Frame, same vision->track->scene->publish\n  \
         pipeline (a renderer pipes frames straight in for the real-time closed loop). The <video> positional is then\n  \
         ignored (pass '-'). e.g.  cat frames.rgb | third-eye scene - --rgb-stream 640x360@24 --static-cam"
    );
    std::process::exit(1);
}

/// The capstone: the whole engine as one self-pacing loop. The cadence stride controller paces the
/// full perception+publish per-frame work to the target real-time rate, shedding frames under load.
fn run_pipeline(rest: &[String]) {
    use std::time::Instant;
    use third_eye::pipeline::{PerceptionCore, PerceptionOpts};
    use third_eye::publish::decode_tick;

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = Some((480, 270));
    let mut max_frames: Option<u64> = None;
    let mut target_fps = 30.0f64;
    let mut out = String::from("/tmp/third_eye.aeon");
    let mut verbose = false;
    let mut rgb_stream: Option<String> = None;
    let mut static_cam = false;
    // OPTIONAL motion-deblur pre-pass (default OFF). `--motion-deblur` enables it; without an explicit
    // --motion-deblur-angle/--motion-deblur-length the PSF is auto-estimated per frame. The env var
    // THIRD_EYE_MOTION_DEBLUR=1 enables it too (the recon node flips it without a flag).
    let mut motion_deblur = std::env::var("THIRD_EYE_MOTION_DEBLUR")
        .ok()
        .map(|v| matches!(v.trim().to_ascii_lowercase().as_str(), "1" | "true" | "yes" | "on"))
        .unwrap_or(false);
    let mut md_angle: Option<f32> = None;
    let mut md_length: Option<f32> = None;
    let mut md_iters: u32 = 24;
    // Pin the cadence stride to 1 (process EVERY input frame, no host-side frame-skip). This is the
    // deterministic, host-paces-its-own-cadence mode — exactly the wasm `PerceptionEngine` contract
    // (the host decides which frames to feed; the lib perceives each one). It makes the bin's `--out`
    // tick stream byte-identical to the wasm `tick_ptr` stream over the same frames+pts (parity).
    let mut no_cadence = false;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--rgb-stream" => { rgb_stream = rest.get(i + 1).cloned(); i += 2; }
            "--target-fps" => { if let Some(f) = rest.get(i + 1).and_then(|s| s.parse().ok()) { target_fps = f; } i += 2; }
            "--out" => { if let Some(o) = rest.get(i + 1) { out = o.clone(); } i += 2; }
            "--static-cam" => { static_cam = true; i += 1; }
            "--motion-deblur" => { motion_deblur = true; i += 1; }
            "--motion-deblur-angle" => { md_angle = rest.get(i + 1).and_then(|s| s.parse().ok()); motion_deblur = true; i += 2; }
            "--motion-deblur-length" => { md_length = rest.get(i + 1).and_then(|s| s.parse().ok()); motion_deblur = true; i += 2; }
            "--motion-deblur-iters" => { if let Some(n) = rest.get(i + 1).and_then(|s| s.parse().ok()) { md_iters = n; } i += 2; }
            "--no-cadence" => { no_cadence = true; i += 1; }
            "--verbose" => { verbose = true; i += 1; }
            _ => i += 1,
        }
    }

    // The raw-stream path supplies its own WxH@fps; the mp4 path is downscaled to `scale` for
    // throughput. Disable the decode-time scale when reading a raw stream (the renderer already
    // emits the dims it wants).
    if rgb_stream.is_some() { scale = None; }
    let input = FrameInput::open("run", &path, rgb_stream.as_deref(), decode_fps, scale, max_frames);
    eprintln!("third-eye run: source = {}", input.source);
    let source_fps = input.fps;
    let dec = input.iter;

    // SINGLE SOURCE OF TRUTH: the bin's `run` perception is the SAME `PerceptionCore` the wasm
    // `PerceptionEngine` drives (`pipeline.rs`) — detect -> track -> scene.update -> scene_to_tick ->
    // encode_tick, plus the gnosis-frf value-door + gnosis-antiqueue corridor per frame. Routing the
    // bin through the core (instead of re-inlining the sequence) is what makes native ⇄ wasm parity
    // hold BY CONSTRUCTION: the `--out` stream here is byte-identical to the wasm `tick_ptr` stream.
    // Build the optional motion-deblur pre-pass config. OFF unless --motion-deblur / env enabled it.
    // An explicit angle OR length switches off auto-estimation and uses the supplied PSF.
    let motion_deblur_opts = if motion_deblur {
        use third_eye::pipeline::MotionDeblurOpts;
        let explicit = md_angle.is_some() || md_length.is_some();
        let cfg = MotionDeblurOpts {
            auto: !explicit,
            angle_deg: md_angle.unwrap_or(0.0),
            length_px: md_length.unwrap_or(9.0),
            iterations: md_iters,
        };
        eprintln!(
            "third-eye run: motion-deblur ON ({})",
            if cfg.auto { "auto PSF per frame".to_string() }
            else { format!("angle {:.1}deg length {:.1}px", cfg.angle_deg, cfg.length_px) }
        );
        Some(cfg)
    } else {
        None
    };
    let opts = PerceptionOpts {
        static_cam, // a fixed camera does not pan; disables global-motion compensation (vision.compensate=false)
        source_id: "third-eye".to_string(),
        layer_id: "perception".to_string(),
        motion_deblur: motion_deblur_opts,
        ..PerceptionOpts::default()
    };
    let (init_w, init_h) = (0u32, 0u32); // dims are advisory; each Frame carries its own
    let mut core = match PerceptionCore::new(init_w, init_h, source_fps, &opts) {
        Ok(c) => c,
        Err(e) => { eprintln!("third-eye run: {e}"); std::process::exit(1); }
    };

    // Cadence stride controller over the FULL per-frame perception+publish work.
    let budget_ns = 1.0e9 / target_fps;
    let mut stride: u32 = 1;
    let mut sel: u32 = 0;
    let mut stream: Vec<u8> = Vec::new();
    let mut seq = 0u32;
    let (mut decoded, mut processed, mut skipped) = (0u64, 0u64, 0u64);
    let (mut total_entities, mut total_declined) = (0u64, 0u64);
    let mut proc_acc = 0.0f64;
    let mut last_knowledge = 0usize;
    let t0 = Instant::now();

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye run: {e}"); break; } };
        decoded += 1;
        if sel % stride != 0 { skipped += 1; sel += 1; continue; }
        sel += 1;

        // ONE perceive: the exact core the wasm engine runs (governor + full pipeline + encode).
        let pts_s = fr.pts_s;
        let frame: third_eye::frame::Frame = fr.into();
        let t = Instant::now();
        let packed = core.observe_packed(&frame, pts_s);
        let dt = t.elapsed().as_secs_f64();
        proc_acc += dt;

        let acc = core.accepted();
        total_entities += acc as u64;
        total_declined += core.scene().declined;
        last_knowledge = core.scene().knowledge.len();
        stream.extend_from_slice(&packed);
        processed += 1;
        seq += 1;

        // Controller: real per-frame cost vs the real-time budget. With --no-cadence the stride is
        // pinned at 1 (every frame processed; the host owns pacing — the wasm-engine contract).
        let per_frame_ns = dt * 1.0e9;
        let old = stride;
        if !no_cadence {
            if per_frame_ns > budget_ns { stride = (stride + 1).min(240); }
            else if per_frame_ns < budget_ns * 0.5 && stride > 1 { stride -= 1; }
        }
        if verbose && (processed % 20 == 0 || old != stride) {
            eprintln!(
                "seq {:>4} pts {:.2}s : {} entities  {:.2} ms/frame  stride {}->{}  knowledge {}",
                seq, pts_s, acc, per_frame_ns / 1.0e6, old, stride, last_knowledge
            );
        }
    }
    let wall = t0.elapsed().as_secs_f64();
    let _ = std::fs::write(&out, &stream);

    // Round-trip integrity.
    let mut off = 0usize; let mut rt = 0u64;
    while let Some((_t, read)) = decode_tick(&stream, off) { off += read; rt += 1; }

    let proc_fps = if proc_acc > 0.0 { processed as f64 / proc_acc } else { 0.0 };
    println!("third-eye run report (full cadence-governed pipeline)");
    println!("  decoded          : {decoded}");
    println!("  processed        : {processed}");
    println!("  skipped (cadence): {skipped}");
    println!("  converged stride : {stride}  (effective {:.1} fps)", source_fps / stride as f64);
    println!("  perception rate  : {proc_fps:.1} frames/s (full pipeline, cold)");
    println!("  wall             : {wall:.3}s");
    println!("  entities emitted : {total_entities} (Accept-only)");
    println!("  declined facts   : {total_declined}");
    println!("  certified preds  : {last_knowledge} (final tick)");
    println!("  aeon stream      : {seq} frames, {} bytes -> {out}", stream.len());
    println!("  round-trip       : {rt}/{seq} frames decode, consumed {off}/{} bytes", stream.len());
    println!("  -> feed this stream into worldsim WorldState.entities; perceiveWorld(thoth) reads it as reality.");
}

fn run_publish(rest: &[String]) {
    use frffmpeg::decode::{DecodeOptions, Decoder, probe};
    use third_eye::physics::PhysicsConfig;
    use third_eye::publish::{WorldMapping, decode_tick, encode_tick, scene_to_tick, THIRD_EYE_STREAM_ID};
    use third_eye::scene::SceneModel;
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut out = String::from("/tmp/third_eye.aeon");
    let mut verbose = false;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--out" => { if let Some(o) = rest.get(i + 1) { out = o.clone(); } i += 2; }
            "--verbose" => { verbose = true; i += 1; }
            _ => i += 1,
        }
    }

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => { eprintln!("third-eye publish: probe failed: {e}"); std::process::exit(1); }
    };
    let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => { eprintln!("third-eye publish: open failed: {e}"); std::process::exit(1); }
    };

    let mut bg = BackgroundModel::new();
    let vcfg = VisionConfig::default();
    let mut tracker = Tracker::new(TrackerConfig::default());
    let mut scene = SceneModel::new(PhysicsConfig::default());
    let map = WorldMapping::default();

    let mut stream: Vec<u8> = Vec::new();
    let mut seq = 0u32;
    let mut frames = 0u64;
    let mut total_entities = 0u64;
    let mut nonempty_frames = 0u64;

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye publish: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        scene.update(&tracker);
        let tick = scene_to_tick(&scene, seq, "third-eye", "perception", fr.pts_s, &map);
        let acc = scene.accepted();
        if acc > 0 { nonempty_frames += 1; total_entities += acc as u64; }
        if verbose && acc > 0 {
            eprintln!("seq {:>4} pts {:.2}s : {} entities, {} payload bytes", seq, fr.pts_s, acc, tick.payload.len());
        }
        stream.extend_from_slice(&encode_tick(&tick));
        seq += 1;
    }

    if let Err(e) = std::fs::write(&out, &stream) {
        eprintln!("third-eye publish: write {out}: {e}");
        std::process::exit(1);
    }

    // Round-trip: decode the stream back and verify every frame parses + targets the right stream.
    let mut off = 0usize;
    let mut decoded = 0u64;
    let mut bad = 0u64;
    let mut sample_payload: Option<String> = None;
    while let Some((t, read)) = decode_tick(&stream, off) {
        if t.stream_id != THIRD_EYE_STREAM_ID { bad += 1; }
        if !t.payload.windows(15).any(|w| w == b"\"worldsim-state") { bad += 1; }
        if sample_payload.is_none() && t.payload.len() > 60 {
            sample_payload = Some(String::from_utf8_lossy(&t.payload).into_owned());
        }
        off += read;
        decoded += 1;
    }

    println!("third-eye publish report");
    println!("  frames in        : {frames}");
    println!("  aeon frames out  : {seq} (stream id 0x{THIRD_EYE_STREAM_ID:04x})");
    println!("  frames w/ entities: {nonempty_frames}");
    println!("  total entities   : {total_entities} (Accept-verdict objects only)");
    println!("  stream bytes     : {} -> {out}", stream.len());
    println!("  round-trip       : decoded {decoded} frames, {bad} malformed, consumed {off}/{} bytes", stream.len());
    if let Some(p) = sample_payload {
        let trunc: String = p.chars().take(400).collect();
        println!("  sample frame     : {trunc}");
    }
}

fn run_scene(rest: &[String]) {
    use third_eye::physics::PhysicsConfig;
    use third_eye::scene::SceneModel;
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut verbose = false;
    let mut c_max: Option<f32> = None;
    let mut static_cam = false;
    let mut rgb_stream: Option<String> = None;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--c-max" => { c_max = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--rgb-stream" => { rgb_stream = rest.get(i + 1).cloned(); i += 2; }
            "--static-cam" => { static_cam = true; i += 1; }
            "--verbose" => { verbose = true; i += 1; }
            _ => i += 1,
        }
    }

    let input = FrameInput::open("scene", &path, rgb_stream.as_deref(), decode_fps, scale, max_frames);
    eprintln!("third-eye scene: source = {}", input.source);
    let dec = input.iter;

    let mut bg = BackgroundModel::new();
    let mut vcfg = VisionConfig::default();
    if static_cam { vcfg.compensate = false; }
    let mut tracker = Tracker::new(TrackerConfig::default());
    let mut pcfg = PhysicsConfig::default();
    if let Some(c) = c_max { pcfg.c_max = c; }
    let mut scene = SceneModel::new(pcfg);
    let mut frames = 0u64;
    let mut total_declined = 0u64;
    let mut peak_accepted = 0usize;
    let mut peak_moving = 0usize;
    let mut peak_objects = 0usize;
    // Clip-level tally of WHY objects abstained (the informative-abstain win), counted per tick on
    // the live objects so a non-rigid hand shows up even though it never certifies a regime.
    use third_eye::object_intel::AbstainReason;
    use std::collections::BTreeMap;
    let mut reason_ticks: BTreeMap<&'static str, u64> = BTreeMap::new();

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye scene: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        scene.update(&tracker);
        total_declined += scene.declined;
        peak_accepted = peak_accepted.max(scene.accepted());
        let si = scene.scene_intel();
        peak_moving = peak_moving.max(si.n_moving);
        peak_objects = peak_objects.max(si.n_objects);
        for (o, _) in scene.objects() {
            if o.profile.abstain_reason != AbstainReason::None {
                *reason_ticks.entry(o.profile.abstain_reason.as_str()).or_default() += 1;
            }
        }
        if verbose && scene.round % 20 == 0 {
            eprintln!(
                "frame {:>4} pts {:.2}s : {} | accept {} abstain {} decline {}",
                fr.index, fr.pts_s, si.headline(), scene.accepted(), scene.abstained(), scene.declined
            );
        }
    }

    println!("third-eye scene report");
    println!("  frames           : {frames}");
    println!("  accepted (peak)  : {peak_accepted} objects fully certified");
    println!("  accepted (final) : {}", scene.accepted());
    println!("  abstained (final): {} (present, not provably known)", scene.abstained());
    println!("  declined (total) : {total_declined} kinematic facts rejected (e.g. superluminal jumps)");
    println!("  certified preds  : {}", scene.knowledge.len());

    // ===== SCENE-LEVEL RELATIONAL READ (robust to every object's regime abstaining) =====
    let si = scene.scene_intel();
    let grabs = scene.grab_relations();
    println!();
    println!("  scene structure  : peak {peak_objects} tracked, {peak_moving} moving (final tick: {} tracked, {} moving)", si.n_objects, si.n_moving);
    // Informative-abstain tally: WHY objects abstained over the clip.
    if reason_ticks.is_empty() {
        println!("  abstain reasons  : (none — regimes certified or no abstaining objects)");
    } else {
        let parts: Vec<String> = reason_ticks.iter().map(|(k, v)| format!("{k} ({v} obj-ticks)")).collect();
        println!("  abstain reasons  : {}", parts.join(", "));
        println!("                     (informative abstain: a non_rigid_actuated object exists+moves but is deforming/actuated,");
        println!("                      not a free rigid body — so it reads non-rigid rather than bare 'abstain')");
    }
    // Detected manipulation/grab relations (sustained contact + correlated co-motion).
    if grabs.is_empty() {
        if peak_objects >= 2 {
            println!("  relations        : no sustained-contact grab/manipulation detected (objects never co-moved in sustained contact,");
            println!("                     or the two bodies merged into one silhouette through contact — a tracking limitation, not a grab)");
        } else {
            println!("  relations        : single tracked object — no pair to relate (a grab needs two tracks)");
        }
    } else {
        println!("  relations        : {} grab/manipulation relation(s) detected:", grabs.len());
        for g in grabs {
            println!("    {}", g.summary());
        }
    }

    // ===== ONE-LINE HEADLINE (the useful real-footage summary) =====
    println!();
    println!("  headline         : {}", si.headline());
    println!();
    println!("  honest bounds: the scene structure (count moving, grab relations) is a DETECTED read from proximity +");
    println!("                 co-motion, RELATIVE-scale + in-plane — NOT a conservation certificate. A grab is gated on");
    println!("                 sustained contact + correlated motion; it is honestly NOT a two-body momentum-conservation");
    println!("                 claim (the actuating muscle is unobserved). If the hand occludes/merges the controller into");
    println!("                 one silhouette, there is no pair and the grab ABSTAINS (we never invent it). The per-object");
    println!("                 informative abstain still applies to whatever tracks.");
    println!();
    // Sample a few certified predicates with their law provenance.
    println!("  sample certified knowledge:");
    for (p, law) in scene.knowledge.provenance.iter().take(8) {
        println!("    {p:?}  <-  {law}");
    }
    // Demonstrate the CRDT carve-meet: merging the picture with itself is idempotent;
    // merging with an empty observer yields nothing (only mutually-certified survives).
    let self_meet = scene.knowledge.meet(&scene.knowledge);
    let empty = third_eye::knowledge::CertifiedKnowledge::new();
    let empty_meet = scene.knowledge.meet(&empty);
    println!(
        "  CRDT meet check  : self-meet {} (== {} idempotent), meet-empty {} (== 0 conservative)",
        self_meet.len(),
        scene.knowledge.len(),
        empty_meet.len()
    );
}

/// CERTIFIED AGENCY: run detect+track+scene over the clip, then report what Thoth can DO with each
/// certified object — the manual affordance (graspable / pushable / droppable, or an honest
/// abstain/decline) derived from the object's certified rigid-body profile, plus a sample
/// COUNTERFACTUAL (the certified outcome of arresting the body). third-eye runs NO force solver: an
/// affordance is a GATE on the already-proven profile (regime stable + clean abstain_reason + size
/// within reach + impulse arrestable), and the counterfactual is the forward image of the conserved
/// momentum under a canceling impulse, lightcone-gated. Everything RELATIVE / in-plane / conditional.
fn run_affordances(rest: &[String]) {
    use frffmpeg::decode::{DecodeOptions, Decoder, probe};
    use third_eye::affordance::{AffordanceConfig, affordance_summary};
    use third_eye::physics::{PhysicsConfig, Verdict};
    use third_eye::scene::SceneModel;
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut verbose = false;
    let mut c_max: Option<f32> = None;
    let mut static_cam = false;
    let mut priors_path: Option<String> = None;
    let mut hand_reach: Option<f32> = None;
    let mut max_impulse: Option<f32> = None;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--c-max" => { c_max = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--object-priors" => { priors_path = rest.get(i + 1).cloned(); i += 2; }
            "--hand-reach" => { hand_reach = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--max-impulse" => { max_impulse = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--static-cam" => { static_cam = true; i += 1; }
            "--verbose" => { verbose = true; i += 1; }
            _ => i += 1,
        }
    }

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => { eprintln!("third-eye affordances: probe failed: {e}"); std::process::exit(1); }
    };
    let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => { eprintln!("third-eye affordances: open failed: {e}"); std::process::exit(1); }
    };

    let mut bg = BackgroundModel::new();
    let mut vcfg = VisionConfig::default();
    if static_cam { vcfg.compensate = false; }
    let mut tracker = Tracker::new(TrackerConfig::default());
    let mut pcfg = PhysicsConfig::default();
    if let Some(c) = c_max { pcfg.c_max = c; }
    let mut scene = SceneModel::new(pcfg);
    let _ = AffordanceConfig::default(); // config is owned by SceneModel; flags below tune it
    if hand_reach.is_some() || max_impulse.is_some() {
        scene.set_affordance_config(hand_reach, max_impulse);
    }
    let mut priors_loaded = 0usize;
    if let Some(pp) = &priors_path {
        match third_eye::priors::PriorSet::load(pp) {
            Ok(set) => { priors_loaded = set.len(); scene.set_priors(set); }
            Err(e) => { eprintln!("third-eye affordances: --object-priors {pp}: {e}"); std::process::exit(1); }
        }
    }

    let mut frames = 0u64;
    let mut peak_graspable = 0usize;
    let mut peak_admissible = 0usize;
    // Clip-level tally of affordance verdicts by kind (peak per tick is the useful summary).
    use std::collections::BTreeMap;
    let mut kind_ticks: BTreeMap<&'static str, u64> = BTreeMap::new();
    let mut abstain_ticks = 0u64;

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye affordances: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        scene.update(&tracker);
        let affs = scene.affordances();
        let admissible = affs.iter().filter(|a| a.admissible()).count();
        let graspable = affs.iter().filter(|a| a.admissible() && a.kind == third_eye::affordance::AffordanceKind::Graspable).count();
        peak_admissible = peak_admissible.max(admissible);
        peak_graspable = peak_graspable.max(graspable);
        for a in affs {
            match a.verdict {
                Verdict::Accept => *kind_ticks.entry(a.kind.as_str()).or_default() += 1,
                Verdict::Abstain => abstain_ticks += 1,
                Verdict::Decline => {}
            }
        }
        if verbose && !affs.is_empty() {
            eprintln!("frame {:>4} pts {:.2}s : {}", fr.index, fr.pts_s, affordance_summary(affs));
        }
    }

    println!("third-eye affordances report (CERTIFIED AGENCY: what Thoth can DO from what he can PROVE)");
    println!("  decoded frames   : {frames}");
    if priors_path.is_some() {
        println!("  grounding        : {priors_loaded} recon material prior(s) -> impulse budgets material-weighted");
    } else {
        println!("  grounding        : no recon priors -> relative-equal-density (impulse budgets relative)");
    }
    println!("  peak admissible  : {peak_admissible} affordance(s) in a tick ({peak_graspable} graspable)");
    let parts: Vec<String> = kind_ticks.iter().map(|(k, v)| format!("{k} ({v} obj-ticks)")).collect();
    println!("  admissible kinds : {}", if parts.is_empty() { "(none certified)".to_string() } else { parts.join(", ") });
    println!("  abstained        : {abstain_ticks} obj-ticks (regime forced/unresolved OR non-rigid/actuated OR unreliable — Thoth declines to act)");
    println!();

    // Final-tick certified affordances + a sample counterfactual.
    let affs = scene.affordances();
    let cfs = scene.counterfactuals();
    if affs.is_empty() {
        println!("  final tick       : no confirmed objects to assess.");
    } else {
        println!("  final-tick affordances (verdict carried verbatim — honest agency):");
        for a in affs {
            println!("    {}", a.summary());
        }
    }
    if let Some(c) = cfs.first() {
        println!();
        println!("  sample counterfactual (the certified outcome of arresting an admissible-grasp body):");
        println!("    {}", c.summary());
    }
    println!();
    println!("  honest bounds: an affordance is a GATE on the already-certified profile (NO force solver, NO ML). The");
    println!("                 C2-shadow gate is prescriptive: a non-rigid/actuated body (a hand) or an unreliable read");
    println!("                 ABSTAINS — Thoth does NOT grab a hand. Size/impulse gates are RELATIVE (within-scene), so a");
    println!("                 'too big' / 'too much momentum' DECLINE is a structural verdict, not absolute kg/metre. The");
    println!("                 counterfactual is the forward image of the conserved momentum under a canceling impulse,");
    println!("                 lightcone-gated; the post-impulse regime ABSTAINS until enough free-continuation frames");
    println!("                 would accrue. Every clause cites a green gnosis-math law (fork_preserves_charge / lightcone).");
}

/// THE C0-C3 METACOGNITIVE GATE (the keystone of Thoth's mind): run detect+track+scene over the clip,
/// and for EVERY perceptual tick compute the metacognitive state mirroring `NeurosymbolicToolUseMarkov`
/// — C0 raw observation, C1 certified-gnosis SCORE (Accept-only, E8-quantized), C2 carried-forward
/// SHADOW + open symbolic OBLIGATIONS, C3 framework AUDIT (plateau / regression / bias). The discipline
/// `disciplined = (score rose) OR (shadow exposed)` is ENFORCED every tick (`debug_assert!`), the
/// runtime mirror of `no_gain_disciplined_step_exposes_shadow`: Thoth cannot hide a non-improving
/// observation. Prints the per-tick C0-C3 walk + a final summary. RELATIVE / Accept-only / honest.
fn run_metacog(rest: &[String]) {
    use frffmpeg::decode::{DecodeOptions, Decoder, probe};
    use third_eye::metacog::MetacogLayer;
    use third_eye::physics::PhysicsConfig;
    use third_eye::scene::SceneModel;
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut verbose = false;
    let mut c_max: Option<f32> = None;
    let mut static_cam = false;
    let mut priors_path: Option<String> = None;
    let mut plateau_window: Option<u32> = None;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--c-max" => { c_max = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--object-priors" => { priors_path = rest.get(i + 1).cloned(); i += 2; }
            "--plateau-window" => { plateau_window = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--static-cam" => { static_cam = true; i += 1; }
            "--verbose" => { verbose = true; i += 1; }
            _ => i += 1,
        }
    }

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => { eprintln!("third-eye metacog: probe failed: {e}"); std::process::exit(1); }
    };
    let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => { eprintln!("third-eye metacog: open failed: {e}"); std::process::exit(1); }
    };

    let mut bg = BackgroundModel::new();
    let mut vcfg = VisionConfig::default();
    if static_cam { vcfg.compensate = false; }
    let mut tracker = Tracker::new(TrackerConfig::default());
    let mut pcfg = PhysicsConfig::default();
    if let Some(c) = c_max { pcfg.c_max = c; }
    let mut scene = SceneModel::new(pcfg);
    if let Some(w) = plateau_window { scene.set_metacog_plateau_window(w); }
    // RECON -> THIRD-EYE FEEDBACK: with material priors the C3 bias (verdict-flip) check can fire,
    // since a grounded certified collision can read differently from the equal-density assumption.
    let mut priors_loaded = 0usize;
    if let Some(pp) = &priors_path {
        match third_eye::priors::PriorSet::load(pp) {
            Ok(set) => { priors_loaded = set.len(); scene.set_priors(set); }
            Err(e) => { eprintln!("third-eye metacog: --object-priors {pp}: {e}"); std::process::exit(1); }
        }
    }

    // Per-tick C0-C3 walk + running tallies.
    let mut frames = 0u64;
    let mut ticks = 0u64;
    let mut observed_ticks = 0u64; // ticks that actually perceived >=1 object
    let mut empty_ticks = 0u64;    // empty-percept ticks (vacuously disciplined)
    let mut disciplined_all = true;
    let mut peak_score = 0u64;
    let mut peak_shadow = 0u64;
    let mut gain_ticks = 0u64;     // SyntheticGnosisIncreases
    let mut shadow_ticks = 0u64;   // ShadowExposed (no gain but shadow carried)
    let mut plateau_ticks = 0u64;
    let mut regression_ticks = 0u64;
    let mut bias_ticks = 0u64;
    use std::collections::BTreeMap;
    let mut layer_hist: BTreeMap<&'static str, u64> = BTreeMap::new();
    let print_walk = verbose; // the full per-tick walk is verbose; otherwise we sample + summarise.

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye metacog: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        scene.update(&tracker);
        if let Some(m) = scene.metacog() {
            ticks += 1;
            disciplined_all &= m.disciplined;
            peak_score = peak_score.max(m.score);
            peak_shadow = peak_shadow.max(m.shadow);
            if m.observed > 0 { observed_ticks += 1; } else { empty_ticks += 1; }
            if m.synthetic_gnosis_increases() { gain_ticks += 1; }
            else if m.shadow_exposed() { shadow_ticks += 1; }
            if m.audit.plateau { plateau_ticks += 1; }
            if m.audit.regression { regression_ticks += 1; }
            if m.audit.bias { bias_ticks += 1; }
            *layer_hist.entry(m.layer.as_str()).or_default() += 1;
            // Print the per-tick walk verbosely, or sample every 20th OBSERVED tick (+ any audit tick)
            // otherwise, so the C0-C3 walk over the real percept is visible without flooding on the
            // empty warm-up ticks of a long clip.
            let audit_tick = m.audit.plateau || m.audit.regression || m.audit.bias;
            if print_walk || (m.observed > 0 && observed_ticks % 20 == 0) || audit_tick {
                println!("  {}", m.line());
            }
        }
    }

    println!();
    println!("third-eye metacog report (C0-C3 metacognitive gate per perceptual tick)");
    println!("  decoded frames   : {frames}");
    println!("  metacog ticks    : {ticks} (each ran all four C0-C3 stages)");
    println!("  observed ticks   : {observed_ticks} (perceived >=1 object); empty ticks: {empty_ticks} (vacuously disciplined)");
    if priors_path.is_some() {
        println!("  grounding        : {priors_loaded} recon material prior(s) -> C3 bias (verdict-flip) check active");
    } else {
        println!("  grounding        : no recon priors -> C3 bias check inert (no grounded read to disagree with)");
    }
    println!();
    println!("  DISCIPLINE       : disciplined every tick = {} (the runtime mirror of", if disciplined_all { "YES" } else { "NO" });
    println!("                     no_gain_disciplined_step_exposes_shadow: a tick that did not raise the");
    println!("                     certified-gnosis score MUST expose residual shadow. Thoth cannot hide a");
    println!("                     non-improving observation.)");
    println!("  C1 score (peak)  : {peak_score} (Accept-only weighted certified predicates, E8-quantized)");
    println!("  C2 shadow (peak) : {peak_shadow} (carried-forward abstain mass; never silently dropped)");
    println!("  gain ticks       : {gain_ticks} (SyntheticGnosisIncreases: score rose)");
    println!("  shadow-only ticks: {shadow_ticks} (no gain, shadow exposed => still disciplined)");
    println!("  C3 audit         : plateau {plateau_ticks}, regression {regression_ticks}, bias {bias_ticks} (tick(s))");
    let layers: Vec<String> = layer_hist.iter().map(|(k, v)| format!("{k}={v}")).collect();
    println!("  layer histogram  : {}", if layers.is_empty() { "(no ticks)".to_string() } else { layers.join(" ") });
    println!();
    println!("  honest bounds: the C1 score rewards ONLY Accept certified predicates (abstains contribute ZERO — no");
    println!("                 inflation). C2 shadow is CARRIED FORWARD in a running accumulator and only falls when its");
    println!("                 abstain mass is actually re-certified away, never by forgetting. The E8 quantization MIRRORS");
    println!("                 the certified e8_quantizer::nearest_e8 decoder (Gnosis.E8Lattice SSOT) so a plateau is a");
    println!("                 principled flat E8 cell, not float wobble. C3 bias NAMES a framework (equal-density)");
    println!("                 verdict-flip; it does not claim which read is true.");
    let _ = MetacogLayer::C0; // (layer enum referenced for the histogram strings above)
    if !disciplined_all {
        std::process::exit(1);
    }
}

/// Multi-object INTERACTION intelligence: run detect+track+scene over the clip, then report every
/// detected pairwise interaction — CERTIFIED collisions (total momentum conserved, §7.5-style ACCEPT
/// citing fork_preserves_charge), classified ELASTIC vs INELASTIC by total KE (information_conservation),
/// DECLINED pairs (total momentum NOT conserved => not a clean isolated pair), and ABSTAINED events
/// (before/after momentum unreadable through contact — the honest tracking-limitation path). All
/// quantities RELATIVE (see object_intel header); the certified output is the conservation STRUCTURE.
fn run_interactions(rest: &[String]) {
    use frffmpeg::decode::{DecodeOptions, Decoder, probe};
    use third_eye::physics::{PhysicsConfig, Verdict};
    use third_eye::scene::SceneModel;
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut verbose = false;
    let mut static_cam = false;
    let mut c_max: Option<f32> = None;
    let mut priors_path: Option<String> = None;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--c-max" => { c_max = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--object-priors" => { priors_path = rest.get(i + 1).cloned(); i += 2; }
            "--static-cam" => { static_cam = true; i += 1; }
            "--verbose" => { verbose = true; i += 1; }
            _ => i += 1,
        }
    }

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => { eprintln!("third-eye interactions: probe failed: {e}"); std::process::exit(1); }
    };
    let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => { eprintln!("third-eye interactions: open failed: {e}"); std::process::exit(1); }
    };

    let mut bg = BackgroundModel::new();
    let mut vcfg = VisionConfig::default();
    if static_cam { vcfg.compensate = false; }
    let mut tracker = Tracker::new(TrackerConfig::default());
    let mut pcfg = PhysicsConfig::default();
    if let Some(c) = c_max { pcfg.c_max = c; }
    let mut scene = SceneModel::new(pcfg);
    // RECON -> THIRD-EYE FEEDBACK: load per-track MATERIAL/MASS/INERTIA priors so the physics is
    // GROUNDED with real material-weighted masses (mass = material_density × volume) instead of the
    // relative DENSITY_GUESS = 1.0. Absent => relative-equal-density (the original behaviour).
    let mut priors_loaded = 0usize;
    let mut priors_have_scale = false;
    if let Some(pp) = &priors_path {
        match third_eye::priors::PriorSet::load(pp) {
            Ok(set) => {
                priors_loaded = set.len();
                priors_have_scale = set.has_scale_ref();
                scene.set_priors(set);
            }
            Err(e) => { eprintln!("third-eye interactions: --object-priors {pp}: {e}"); std::process::exit(1); }
        }
    }
    let mut frames = 0u64;
    let mut peak_confirmed = 0usize;

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye interactions: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        scene.update(&tracker);
        peak_confirmed = peak_confirmed.max(scene.objects.len());
        if verbose {
            let forced: Vec<u64> = scene.objects.iter()
                .filter(|(o, _)| o.profile.regime == third_eye::object_intel::Regime::Forced)
                .map(|(o, _)| o.id).collect();
            if !forced.is_empty() {
                eprintln!("frame {:>4} pts {:.3}s : {} confirmed, forced {:?}", fr.index, fr.pts_s, scene.objects.len(), forced);
            }
        }
    }

    let inters = scene.interactions();
    let n_cert = inters.iter().filter(|x| x.momentum_verdict == Verdict::Accept).count();
    let n_decl = inters.iter().filter(|x| x.momentum_verdict == Verdict::Decline).count();
    let n_abst = inters.iter().filter(|x| x.momentum_verdict == Verdict::Abstain).count();

    println!("third-eye interactions report (CERTIFIED multi-object collision detection)");
    println!("  decoded frames   : {frames}");
    println!("  peak confirmed   : {peak_confirmed} objects");
    if priors_path.is_some() {
        println!(
            "  grounding        : {} recon material prior(s) loaded -> physics MATERIAL-GROUNDED (mass = material_density x volume){}",
            priors_loaded,
            if priors_have_scale { "; absolute-SI scale reference present" } else { "; absolute SI ABSTAINED (no scale ref) -> RATIOS only" }
        );
    } else {
        println!("  grounding        : no recon priors (--object-priors) -> RELATIVE-EQUAL-DENSITY (all objects assumed equal density)");
    }
    println!("  interactions     : {} total ({} certified, {} declined, {} abstain)", inters.len(), n_cert, n_decl, n_abst);

    // One-line headline summary.
    if inters.is_empty() {
        println!("  summary          : no multi-object interactions detected (no simultaneous forced+approaching pair)");
    } else {
        use third_eye::interaction::EnergyClass;
        let cert_elastic = inters.iter().filter(|x| x.certified() && x.energy == EnergyClass::Elastic).count();
        let cert_inelastic = inters.iter().filter(|x| x.certified() && x.energy == EnergyClass::Inelastic).count();
        // Momentum certified but the energy class held (source-less KE read => tracking-read artifact).
        let cert_energy_held = inters.iter().filter(|x| x.certified() && x.energy == EnergyClass::Abstain).count();
        let mut parts: Vec<String> = Vec::new();
        if cert_inelastic > 0 { parts.push(format!("{cert_inelastic} certified inelastic")); }
        if cert_elastic > 0 { parts.push(format!("{cert_elastic} certified elastic")); }
        if cert_energy_held > 0 { parts.push(format!("{cert_energy_held} momentum-certified (energy class held)")); }
        if n_decl > 0 { parts.push(format!("{n_decl} declined (not isolated)")); }
        if n_abst > 0 { parts.push(format!("{n_abst} abstained (tracking limit)")); }
        println!("  summary          : {}", parts.join(", "));
        // Echo the first certified collision's full one-liner as the headline.
        if let Some(first) = inters.iter().find(|x| x.certified()) {
            println!("  headline         : {}", first.summary());
        }
    }
    println!();

    let verdict_str = |v: Verdict| match v {
        Verdict::Accept => "ACCEPT",
        Verdict::Abstain => "abstain",
        Verdict::Decline => "DECLINE",
    };
    for it in inters {
        println!("  interaction #{}+#{}  @pts {:.3}  [momentum: {}]", it.a_id, it.b_id, it.pts, verdict_str(it.momentum_verdict));
        println!("    {}", it.summary());
        if it.momentum_verdict != Verdict::Abstain {
            println!(
                "    momentum  : |p_tot| {:.5} -> {:.5}  (residual {:.1}%)",
                it.p_tot_before, it.p_tot_after, it.p_residual_frac * 100.0
            );
            println!(
                "    energy    : KE_tot {:.6} -> {:.6}  ({} KE lost {:.0}%) => {}",
                it.ke_before, it.ke_after,
                if it.ke_lost_frac >= 0.0 { "rel" } else { "rel-GAIN" },
                it.ke_lost_frac.abs() * 100.0, it.energy.as_str()
            );
        }
        println!("    interaction verdicts (each cites a green gnosis-math law):");
        for f in &it.facts {
            println!("      {:<26} {:<8} <- {}", f.fact, verdict_str(f.verdict), f.law);
            println!("        {}", f.reason);
        }
        println!();
    }
    println!("  honest bounds: with recon priors the masses are MATERIAL-WEIGHTED (mass = material_density x volume),");
    println!("                 so the inter-object MASS RATIO is GROUNDED (plastic vs denser) and the momentum-conservation");
    println!("                 certificate weighs a small dense object and a big light one correctly. Volume is in");
    println!("                 NORMALISED units, so absolute kg/J stay ABSTAINED unless a scale reference is supplied —");
    println!("                 the GROUNDED output is the material-weighted RATIO + the conservation structure + the");
    println!("                 elastic/inelastic class (now also checked against a material restitution prior). Without");
    println!("                 priors everything is RELATIVE-EQUAL-DENSITY. Tracking two objects cleanly THROUGH contact");
    println!("                 is hard; if a track merges/drops at contact the event ABSTAINS (no false certification).");
}

/// CERTIFIED TRAJECTORY PREDICTION: run detect+track+scene over the clip, then report per-object the
/// conditional, regime-gated forecast (ballistic position for free_translation, in-plane director for
/// free_rotation, stays-put for at_rest; forced/abstain => ABSTAIN), its cited conservation law, its
/// validity window, the imminent-collision invalidation, and the SELF-VALIDATION error once the clip
/// reaches each forecast's horizon — the engine grading how well the certified regime actually held.
/// All quantities RELATIVE / in-plane / horizon-bounded (see prediction.rs header).
fn run_predict(rest: &[String]) {
    use frffmpeg::decode::{DecodeOptions, Decoder, probe};
    use third_eye::physics::{PhysicsConfig, Verdict};
    use third_eye::prediction::ForecastKind;
    use third_eye::scene::SceneModel;
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut verbose = false;
    let mut static_cam = false;
    let mut c_max: Option<f32> = None;
    let mut horizon_frames: Option<u32> = None;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--horizon-frames" => { horizon_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--c-max" => { c_max = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--static-cam" => { static_cam = true; i += 1; }
            "--verbose" => { verbose = true; i += 1; }
            _ => i += 1,
        }
    }

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => { eprintln!("third-eye predict: probe failed: {e}"); std::process::exit(1); }
    };
    let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => { eprintln!("third-eye predict: open failed: {e}"); std::process::exit(1); }
    };

    let mut bg = BackgroundModel::new();
    let mut vcfg = VisionConfig::default();
    if static_cam { vcfg.compensate = false; }
    let mut tracker = Tracker::new(TrackerConfig::default());
    let mut pcfg = PhysicsConfig::default();
    if let Some(c) = c_max { pcfg.c_max = c; }
    let mut scene = SceneModel::new(pcfg);
    if let Some(h) = horizon_frames {
        let mut prcfg = third_eye::prediction::PredictionConfig::default();
        prcfg.horizon_frames = h.max(1);
        scene.set_prediction_config(prcfg);
    }
    let mut frames = 0u64;
    let mut peak_confirmed = 0usize;

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye predict: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        scene.update(&tracker);
        peak_confirmed = peak_confirmed.max(scene.objects.len());
        if verbose {
            for (obj, _) in scene.objects() {
                if let Some(f) = scene.predictor().current.get(&obj.id) {
                    if f.verdict == Verdict::Accept {
                        eprintln!("frame {:>4} pts {:.3}s : {}", fr.index, fr.pts_s, f.line());
                    }
                }
            }
        }
    }

    let pred = scene.predictor();
    let hf = pred.config().horizon_frames;

    println!("third-eye predict report (CERTIFIED CONDITIONAL TRAJECTORY PREDICTION + SELF-VALIDATION)");
    println!("  decoded frames   : {frames}");
    println!("  peak confirmed   : {peak_confirmed} objects");
    println!("  horizon          : {hf} frames (conditional on the regime holding; relative-scale; in-plane)");
    println!("  self-validation  : {}", pred.validation_summary());
    println!();

    let verdict_str = |v: Verdict| match v {
        Verdict::Accept => "ACCEPT",
        Verdict::Abstain => "abstain",
        Verdict::Decline => "DECLINE",
    };

    // Per-object: the FINAL live forecast (regime + certified forecast/abstain + cited law + window +
    // any invalidation), followed by that object's self-validations realised over the clip.
    let mut ids: Vec<u64> = pred.current.keys().copied().collect();
    ids.sort_unstable();
    if ids.is_empty() {
        println!("  no confirmed objects to forecast.");
    }
    for id in ids {
        let f = &pred.current[&id];
        println!("  object #{id}  [regime {}]  forecast: {} [{}]", f.regime.as_str(), verdict_str(f.verdict), f.kind.as_str());
        println!("    {}", f.statement);
        println!("    cited law      : {}", f.law);
        println!("    validity window: regime held {} frame(s); horizon {:.3}s (pts {:.3} -> {:.3})", f.held_frames, f.horizon_s, f.issued_pts, f.target_pts);
        if f.invalidated {
            println!("    INVALIDATED    : {}", f.invalidation_reason.clone().unwrap_or_default());
            println!("                     the free-motion forecast was retired (a force/collision intervened); not graded as a conservation failure.");
        }
        // Self-validations realised for this object.
        let vs: Vec<_> = pred.validations.iter().filter(|v| v.id == id).collect();
        if vs.is_empty() {
            println!("    self-validation: (no forecast reached its horizon within the clip)");
        } else {
            // Report the best (smallest realised relative error among non-invalidated grades) and the
            // counts, so the headline number is the engine's own grade of the conservation.
            let graded: Vec<_> = vs.iter().filter(|v| !v.invalidated).collect();
            let acc = vs.iter().filter(|v| v.grade == Verdict::Accept).count();
            let dec = vs.iter().filter(|v| v.grade == Verdict::Decline).count();
            let abs = vs.iter().filter(|v| v.grade == Verdict::Abstain).count();
            println!("    self-validation: {} graded ({acc} accept, {dec} decline, {abs} abstain-invalidated)", vs.len());
            if let Some(best) = graded.iter().min_by(|a, b| a.rel_error.partial_cmp(&b.rel_error).unwrap_or(std::cmp::Ordering::Equal)) {
                let unit = match best.kind { ForecastKind::Orientation => "of a turn", _ => "of scale" };
                println!("                     best realised error {:.4} = {:.1}% {} (regime {} {})",
                    best.raw_error, best.rel_error * 100.0, unit, best.regime.as_str(),
                    if best.grade == Verdict::Accept { "HELD => conservation corroborated" } else { "BROKE => regime mis-certified or a force acted" });
            }
            if abs > 0 {
                println!("                     {abs} forecast(s) abstained: correctly retired by an imminent collision (free motion expired).");
            }
        }
        println!();
    }

    // One-line scene summary.
    let n_obj = peak_confirmed;
    let summ = pred.validation_summary();
    println!("  scene summary    : {n_obj} confirmed object(s); {summ}");
    println!();
    println!("  honest bounds: every forecast is CONDITIONAL (\"IF no new force/torque, THEN ...\") — the forward image of a");
    println!("                 CONSERVATION LAW, not a claim about the future world. It is asserted only after the regime");
    println!("                 has HELD long enough, EXPIRED the moment the object is on a collision course, RELATIVE-scale,");
    println!("                 IN-PLANE (out-of-plane orientation abstains), and HORIZON-bounded. The self-validation error");
    println!("                 is the engine grading ITSELF: small => the certified conservation actually held; large =>");
    println!("                 the regime was mis-certified or an unmodelled force acted. forced/abstain objects get NO");
    println!("                 forecast (honest ABSTAIN — an unresolved or actively-forced object is not predictable).");
}

fn run_detect(rest: &[String]) {
    use third_eye::recon::reconstruct;
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut dump_frame: Option<u64> = None;
    let mut dump_dir = String::from("/tmp/third_eye_meshes");
    let mut verbose = false;
    let mut rgb_stream: Option<String> = None;

    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => {
                decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok());
                i += 2;
            }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) {
                        scale = Some((w, h));
                    }
                }
                i += 2;
            }
            "--max" => {
                max_frames = rest.get(i + 1).and_then(|s| s.parse().ok());
                i += 2;
            }
            "--rgb-stream" => {
                rgb_stream = rest.get(i + 1).cloned();
                i += 2;
            }
            "--dump-frame" => {
                dump_frame = rest.get(i + 1).and_then(|s| s.parse().ok());
                i += 2;
            }
            "--dump-dir" => {
                if let Some(d) = rest.get(i + 1) {
                    dump_dir = d.clone();
                }
                i += 2;
            }
            "--verbose" => {
                verbose = true;
                i += 1;
            }
            _ => i += 1,
        }
    }

    let input = FrameInput::open("detect", &path, rgb_stream.as_deref(), decode_fps, scale, max_frames);
    eprintln!("third-eye detect: source = {}", input.source);
    let dec = input.iter;

    let mut bg = BackgroundModel::new();
    let cfg = VisionConfig::default();
    let mut frames = 0u64;
    let mut total_proposals = 0u64;
    let mut frames_with_props = 0u64;
    let mut max_props = 0usize;
    let mut genus_hist = [0u64; 4]; // 0,1,2,>=3
    let mut fg_sum = 0f64; // mean foreground fraction (camera-motion / over-segmentation signal)

    for fr in dec {
        let fr = match fr {
            Ok(f) => f,
            Err(e) => {
                eprintln!("third-eye detect: {e}");
                break;
            }
        };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, fg_frac) = detect(&fr, &mut bg, &cfg);
        fg_sum += fg_frac as f64;
        if !props.is_empty() {
            frames_with_props += 1;
            total_proposals += props.len() as u64;
            max_props = max_props.max(props.len());
            for p in &props {
                genus_hist[(p.genus as usize).min(3)] += 1;
            }
        }
        if verbose && (props.len() > 0 || fg_frac > 0.6) {
            eprintln!(
                "frame {:>4} pts {:.2}s : {} proposals, fg {:.1}%",
                fr.index,
                fr.pts_s,
                props.len(),
                fg_frac * 100.0
            );
        }
        if Some(fr.index) == dump_frame && !props.is_empty() {
            let _ = std::fs::create_dir_all(&dump_dir);
            for (k, p) in props.iter().enumerate() {
                let (d, mesh) = reconstruct(p);
                let path = format!("{dump_dir}/f{:06}_obj{k:02}_g{}.ply", fr.index, d.genus);
                if std::fs::write(&path, mesh.to_ply()).is_ok() {
                    println!(
                        "  obj {k:02}: genus {} fill {:.2} aspect {:.2} elong {:.2} -> {} verts {} faces -> {}",
                        d.genus,
                        d.fill,
                        d.aspect,
                        d.elongation,
                        mesh.vertex_count(),
                        mesh.face_count(),
                        path
                    );
                }
            }
        }
    }

    let mean_fg = if frames > 0 { fg_sum / frames as f64 } else { 0.0 };
    println!("third-eye detect report");
    println!("  frames          : {frames}");
    println!("  frames w/ props : {frames_with_props}");
    println!("  total proposals : {total_proposals}");
    println!("  max in a frame  : {max_props}");
    println!("  mean fg_frac    : {:.1}% (global apparent motion / over-segmentation)", mean_fg * 100.0);
    println!(
        "  genus hist      : g0={} g1={} g2={} g3+={}",
        genus_hist[0], genus_hist[1], genus_hist[2], genus_hist[3]
    );
}

/// Orientation export: run detect+track, then emit, for the longest confirmed track, a per-frame
/// CSV `frame,pts,cx,cy,orientation_rad,elongation`. This is the read path for the offline
/// spinor-4pi falsification analysis (docs/spinor-4pi-falsification.md). It adds no state to the
/// tracker beyond the per-frame `orientation`/`elongation` the Track now carries.
fn run_orient(rest: &[String]) {
    use frffmpeg::decode::{DecodeOptions, Decoder, probe};
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            _ => i += 1,
        }
    }

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => { eprintln!("third-eye orient: probe failed: {e}"); std::process::exit(1); }
    };
    let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => { eprintln!("third-eye orient: open failed: {e}"); std::process::exit(1); }
    };

    let mut bg = BackgroundModel::new();
    let vcfg = VisionConfig::default();
    let mut tracker = Tracker::new(TrackerConfig::default());

    // Per confirmed-track-id, ordered samples (frame, pts, cx, cy, orientation, elongation).
    use std::collections::HashMap;
    let mut series: HashMap<u64, Vec<(u64, f64, f32, f32, f32, f32)>> = HashMap::new();

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye orient: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        for t in tracker.confirmed() {
            // Only record frames where this track was matched this step (last_pts == this pts).
            if (t.last_pts - fr.pts_s).abs() < 1e-6 {
                series.entry(t.id).or_default().push((
                    fr.index, fr.pts_s, t.x(), t.y(), t.orientation, t.elongation,
                ));
            }
        }
    }

    // Longest confirmed track (most matched frames).
    let Some((id, samples)) = series.iter().max_by_key(|(_, v)| v.len()) else {
        eprintln!("third-eye orient: no confirmed track found");
        std::process::exit(1);
    };
    eprintln!(
        "third-eye orient: longest confirmed track #{id} with {} matched frames (of {} ids)",
        samples.len(),
        series.len()
    );
    println!("frame,pts,cx,cy,orientation_rad,elongation");
    for (frame, pts, cx, cy, ori, elong) in samples {
        println!("{frame},{pts:.6},{cx:.6},{cy:.6},{ori:.6},{elong:.6}");
    }
}

/// Live orientation-as-spinor: run detect+track and report, for the longest confirmed track, the
/// director winding, the half-angle sheet sign and its flips, sheet@2pi / sheet@4pi if a full /
/// double physical turn completed, and the `orientation_spinor_periodicity` audit verdict. This is
/// the engine doing LIVE what the offline /tmp/spinor analysis did from a CSV — the spinor state is
/// maintained incrementally on the Track as it is matched. Audit-only: it never blocks tracking.
fn run_spinor(rest: &[String]) {
    use frffmpeg::decode::{DecodeOptions, Decoder, probe};
    use third_eye::orientation_spinor::{OrientationSpinor, SpinorVerdict};
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            _ => i += 1,
        }
    }

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => { eprintln!("third-eye spinor: probe failed: {e}"); std::process::exit(1); }
    };
    let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => { eprintln!("third-eye spinor: open failed: {e}"); std::process::exit(1); }
    };

    let mut bg = BackgroundModel::new();
    let vcfg = VisionConfig::default();
    let mut tracker = Tracker::new(TrackerConfig::default());

    // Snapshot the spinor state of each confirmed-track id as it is matched. The longest-lived
    // track's final snapshot is the one we audit (it spans the most of the rotation loop).
    use std::collections::HashMap;
    let mut best: HashMap<u64, (u32, OrientationSpinor)> = HashMap::new();
    let mut frames = 0u64;

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye spinor: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        for t in tracker.confirmed() {
            if (t.last_pts - fr.pts_s).abs() < 1e-6 {
                best.insert(t.id, (t.spinor.samples, t.spinor.clone()));
            }
        }
    }

    let Some((id, (_n, sp))) = best.iter().max_by_key(|(_, (n, _))| *n) else {
        eprintln!("third-eye spinor: no confirmed track found");
        std::process::exit(1);
    };
    let audit = sp.audit();

    let fmt_sheet = |o: Option<i8>| match o {
        Some(s) => format!("{s:+}"),
        None => "—".to_string(),
    };
    let verdict_str = match audit.verdict {
        SpinorVerdict::Accept => "ACCEPT",
        SpinorVerdict::Abstain => "ABSTAIN",
        SpinorVerdict::Decline => "DECLINE",
    };

    println!("third-eye spinor report (live orientation-as-spinor; in-plane U(1) sheet)");
    println!("  decoded frames    : {frames}");
    println!("  longest track     : #{id} ({} matched samples, of {} confirmed ids)", sp.samples, best.len());
    println!("  orientation_reliable: {} (false => Nyquist alias or ill-defined axis)", sp.orientation_reliable);
    println!("  max dir step      : {:.2} deg (Nyquist ceiling 90 deg)", sp.max_step.to_degrees());
    println!("  min elongation    : {:.3}", sp.min_elong);
    println!("  director winding  : {:+.4} turns  (W_dir; expect ~1 per physical turn)", audit.w_dir);
    println!("  observable winding: {:+.4} turns  (W_u; winds 2x per physical turn)", audit.w_u);
    println!("  sheet sign now    : {:+}  (half-angle spinor sheet relative to start)", sp.sheet);
    println!("  sheet flips       : {}", audit.sheet_flips);
    println!("  sheet @ 2pi       : {}  (expect -start: flipped after one physical turn)", fmt_sheet(audit.sheet_at_2pi));
    println!("  sheet @ 4pi       : {}  (expect +start: returned after two turns — the 4pi belt-trick)", fmt_sheet(audit.sheet_at_4pi));
    println!("  periodicity audit : {verdict_str}");
    println!("    {}", audit.note);
    println!("  scope             : in-plane U(1) lift of the track PATH (the spinor is the lift).");
    println!("                      Out-of-plane SU(2) needs multi-view and stays abstain.");
}

/// Object intelligence: run detect+track, then for each confirmed track emit a CERTIFIED relative
/// rigid-body dynamical profile — mass(rel)/volume/genus, |v|/p/KE, ω/I/L/rotKE (or abstain), and
/// the REGIME verdict (at_rest / free_translation / free_rotation / forced / abstain) with the
/// gnosis-math law each conservation clause passed. Plus a one-line scene summary. Everything is
/// RELATIVE (no absolute SI scale; density is a coarse guess; inertia is from the 2.5D extruded
/// silhouette; out-of-plane ω stays abstain) — the certified STRUCTURE is the output.
fn run_intel(rest: &[String]) {
    use frffmpeg::decode::{DecodeOptions, Decoder, probe};
    use third_eye::object_intel::{IntelConfig, RigidProfile, profile_with_prior, scene_summary};
    use third_eye::physics::Verdict;
    use third_eye::recon::reconstruct;
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut c_max: f32 = 1.5;
    let mut static_cam = false;
    let mut priors_path: Option<String> = None;
    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--c-max" => { if let Some(c) = rest.get(i + 1).and_then(|s| s.parse().ok()) { c_max = c; } i += 2; }
            "--object-priors" => { priors_path = rest.get(i + 1).cloned(); i += 2; }
            // Fixed-camera footage: skip global-motion (pan) compensation so a single translating
            // object isn't mistaken for a camera pan and suppressed. Use for static-tripod clips.
            "--static-cam" => { static_cam = true; i += 1; }
            _ => i += 1,
        }
    }

    // RECON -> THIRD-EYE FEEDBACK: per-track MATERIAL/MASS/INERTIA priors ground each object's profile
    // (mass = material_density × volume). Absent => relative-equal-density (DENSITY_GUESS = 1.0).
    let priors = match &priors_path {
        Some(pp) => match third_eye::priors::PriorSet::load(pp) {
            Ok(set) => set,
            Err(e) => { eprintln!("third-eye intel: --object-priors {pp}: {e}"); std::process::exit(1); }
        },
        None => third_eye::priors::PriorSet::default(),
    };

    let info = match probe(&path) {
        Ok(i) => i,
        Err(e) => { eprintln!("third-eye intel: probe failed: {e}"); std::process::exit(1); }
    };
    let opts = DecodeOptions { fps: decode_fps, scale, start_s: None, max_frames };
    let dec = match Decoder::open(&path, &info, &opts) {
        Ok(d) => d,
        Err(e) => { eprintln!("third-eye intel: open failed: {e}"); std::process::exit(1); }
    };

    let mut bg = BackgroundModel::new();
    let mut vcfg = VisionConfig::default();
    if static_cam { vcfg.compensate = false; }
    let mut tracker = Tracker::new(TrackerConfig::default());
    let cfg = IntelConfig::default();

    // Per confirmed-track id, keep the latest (track clone, live silhouette descriptor, depth) at the
    // most-recent matched frame — the highest-fidelity geometry for the profile (fill from the real
    // mask, depth from the recon heuristic). The track clone carries the full trajectory + spinor.
    use std::collections::HashMap;
    use third_eye::recon::ObjectDescriptor;
    let mut latest: HashMap<u64, (third_eye::track::Track, ObjectDescriptor, f32)> = HashMap::new();
    let mut frames = 0u64;

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye intel: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        for t in tracker.confirmed() {
            if (t.last_pts - fr.pts_s).abs() >= 1e-6 {
                continue; // only frames where this track was matched this step
            }
            // Recover the matched proposal's silhouette geometry: nearest proposal centroid to the
            // track's filtered position (the association the tracker just made), then reconstruct for
            // the real fill + extrusion depth.
            let mut best: Option<(f32, usize)> = None;
            for (pi, p) in props.iter().enumerate() {
                let d2 = (t.x() - p.cx).powi(2) + (t.y() - p.cy).powi(2);
                if best.map(|(bd, _)| d2 < bd).unwrap_or(true) {
                    best = Some((d2, pi));
                }
            }
            if let Some((_d, pi)) = best {
                let (desc, mesh) = reconstruct(&props[pi]);
                let depth = (0.6 / desc.aspect.max(0.25)).clamp(0.15, 0.9);
                let _ = mesh; // mesh built for parity with detect; volume uses area*depth (silhouette).
                latest.insert(t.id, (t.clone(), desc, depth));
            }
        }
    }

    // Build the certified profile for each confirmed track, ordered by trajectory length (most
    // evidence first).
    let mut profiles: Vec<RigidProfile> = latest
        .values()
        .map(|(t, desc, depth)| profile_with_prior(t, desc, *depth, c_max, &cfg, priors.get(t.id)))
        .collect();
    profiles.sort_by(|a, b| {
        // declined/abstain last; within, more momentum/spin first as a rough "activity" sort.
        b.momentum.partial_cmp(&a.momentum).unwrap_or(std::cmp::Ordering::Equal)
    });

    let verdict_str = |v: Verdict| match v {
        Verdict::Accept => "ACCEPT",
        Verdict::Abstain => "abstain",
        Verdict::Decline => "DECLINE",
    };

    println!("third-eye intel report (certified relative rigid-body dynamical profile)");
    println!("  decoded frames   : {frames}");
    println!("  confirmed tracks : {}", profiles.len());
    println!("  scene summary    : {}", scene_summary(&profiles));
    println!();
    for p in &profiles {
        use third_eye::object_intel::AbstainReason;
        // Informative abstain: when a regime is not a clean free-body certification, annotate WHY so a
        // deforming/actuated body reads "non-rigid/actuated" instead of bare "abstain".
        let regime_line = if p.abstain_reason == AbstainReason::None {
            p.regime.as_str().to_uppercase()
        } else {
            format!("{} — motion: {}", p.regime.as_str().to_uppercase(), p.abstain_reason.phrase())
        };
        println!("  track #{}  [REGIME: {}]  genus {}", p.id, regime_line, p.genus);
        if p.abstain_reason != AbstainReason::None {
            println!(
                "    read      : exists, causal — but {} (momentum spread {:.0}% vs rigid tol; held {} frames)",
                p.abstain_reason.phrase(),
                if p.momentum_spread.is_finite() { p.momentum_spread * 100.0 } else { 0.0 },
                p.hold_frames
            );
        }
        println!(
            "    geometry  : volume(rel) {:.5}  char_size {:.4}  silhouette_area {:.5}  slab_depth {:.3}",
            p.volume, p.char_size, p.silhouette_area, p.depth
        );
        if p.grounded {
            println!(
                "    mass(grnd): {:.5}  I_spin(rel) {:.6}   (MATERIAL-GROUNDED: {} density {:.2} x volume; material-weighted ratio — no absolute SI)",
                p.mass, p.inertia_spin, p.material.as_str(), p.density
            );
        } else {
            println!(
                "    mass(rel) : {:.5}  I_spin(rel) {:.6}   (density guess {:.1}; relative-equal-density — no recon prior, no absolute SI)",
                p.mass, p.inertia_spin, third_eye::object_intel::DENSITY_GUESS
            );
        }
        println!(
            "    linear    : |v| {:.4} u/s   p {:.5}   KE_lin {:.6}",
            p.speed, p.momentum, p.ke_lin
        );
        match (p.omega, p.ang_momentum, p.ke_rot) {
            (Some(w), Some(l), Some(ke)) => println!(
                "    angular   : ω {:+.4} rad/s   L {:.6}   KE_rot {:.6}   (in-plane spin)",
                w, l, ke
            ),
            _ => println!(
                "    angular   : ABSTAIN (out-of-plane / monocular: in-plane lift unreliable — no ω)"
            ),
        }
        println!("    conservation verdicts (each cites a green gnosis-math law):");
        for f in &p.facts {
            println!("      {:<26} {:<8} <- {}", f.fact, verdict_str(f.verdict), f.law);
            println!("        {}", f.reason);
        }
        println!();
    }
    println!("  honest bounds: all quantities RELATIVE (unknown absolute scale + coarse density);");
    println!("                 inertia from the 2.5D extruded silhouette; out-of-plane ω stays abstain.");
    println!("                 The certified output is the REGIME + which conservation laws hold, not SI numbers.");
}

fn run_track(rest: &[String]) {
    use third_eye::track::{Tracker, TrackerConfig};
    use third_eye::vision::{BackgroundModel, VisionConfig, detect};

    let Some(path) = rest.first().cloned() else { usage() };
    let mut decode_fps: Option<f64> = None;
    let mut scale: Option<(u32, u32)> = None;
    let mut max_frames: Option<u64> = None;
    let mut verbose = false;
    let mut rgb_stream: Option<String> = None;

    let mut i = 1;
    while i < rest.len() {
        match rest[i].as_str() {
            "--decode-fps" => { decode_fps = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--scale" => {
                if let Some((w, h)) = rest.get(i + 1).and_then(|s| s.split_once('x')) {
                    if let (Ok(w), Ok(h)) = (w.parse(), h.parse()) { scale = Some((w, h)); }
                }
                i += 2;
            }
            "--max" => { max_frames = rest.get(i + 1).and_then(|s| s.parse().ok()); i += 2; }
            "--rgb-stream" => { rgb_stream = rest.get(i + 1).cloned(); i += 2; }
            "--verbose" => { verbose = true; i += 1; }
            _ => i += 1,
        }
    }

    let input = FrameInput::open("track", &path, rgb_stream.as_deref(), decode_fps, scale, max_frames);
    eprintln!("third-eye track: source = {}", input.source);
    let dec = input.iter;

    let mut bg = BackgroundModel::new();
    let vcfg = VisionConfig::default();
    let mut tracker = Tracker::new(TrackerConfig::default());
    let mut frames = 0u64;
    let mut peak_confirmed = 0usize;

    for fr in dec {
        let fr = match fr { Ok(f) => f, Err(e) => { eprintln!("third-eye track: {e}"); break; } };
        let fr: third_eye::frame::Frame = fr.into();
        frames += 1;
        let (props, _fg) = detect(&fr, &mut bg, &vcfg);
        tracker.step(&props, fr.pts_s);
        let confirmed: Vec<_> = tracker.confirmed().collect();
        peak_confirmed = peak_confirmed.max(confirmed.len());
        if verbose && !confirmed.is_empty() {
            let mut ids: Vec<String> = confirmed
                .iter()
                .map(|t| format!("#{}(v{:.3},{}f)", t.id, t.speed(), t.trajectory.len()))
                .collect();
            ids.truncate(8);
            eprintln!("frame {:>4} pts {:.2}s : {} confirmed [{}]", fr.index, fr.pts_s, confirmed.len(), ids.join(" "));
        }
    }
    // Count distinct confirmed ids ever (approx: current next_id - 1 minus never-confirmed is hard;
    // report current live confirmed + peak).
    let total_ids = tracker.tracks.iter().filter(|t| t.confirmed).count() as u64;

    println!("third-eye track report");
    println!("  frames           : {frames}");
    println!("  peak confirmed   : {peak_confirmed} simultaneous tracks");
    println!("  live confirmed   : {total_ids} at end");
    let mut live: Vec<_> = tracker.tracks.iter().filter(|t| t.confirmed).collect();
    live.sort_by_key(|t| std::cmp::Reverse(t.trajectory.len()));
    for t in live.iter().take(8) {
        println!(
            "    track #{:<4} age {:>4} hits {:>4} traj {:>4}  pos ({:.3},{:.3}) vel ({:+.3},{:+.3}) |v| {:.3} genus {}",
            t.id, t.age, t.hits, t.trajectory.len(), t.x(), t.y(), t.vx(), t.vy(), t.speed(), t.genus
        );
    }
}
